const termo = $('When Executed by Another Workflow').item.json.pergunta_usuario || '';
const limpo = termo.toLowerCase();

let resposta = 'Não encontrei uma página específica, mas você pode ver tudo no nosso site oficial: https://ladyrootsilhagrande.com.br/';

if (limpo.includes('foto') || limpo.includes('suíte') || limpo.includes('suite') || limpo.includes('quarto') || limpo.includes('acomodação')) {
  resposta = 'Você pode conferir todas as fotos e detalhes das nossas suítes aqui: https://ladyrootsilhagrande.com.br/suites/';
}
else if (limpo.includes('passeio') || limpo.includes('roteiro') || limpo.includes('lancha') || limpo.includes('barco')) {
  resposta = 'Conheça nossos roteiros incríveis de lancha por toda a Ilha Grande neste link: https://ladyrootsilhagrande.com.br/passeios/';
}
else if (limpo.includes('restaurante') || limpo.includes('comida') || limpo.includes('cardápio')) {
  resposta = 'Nosso restaurante serve os melhores pratos locais! Descubra mais em: https://ladyrootsilhagrande.com.br/';
}
else if (limpo.includes('transfer') || limpo.includes('passagem') || limpo.includes('chegar')) {
  resposta = 'Trabalhamos com transfer do continente até a Ilha Grande. O valor médio é entre R$ 190 e R$ 210. O atendimento humano pode confirmar os horários.';
}

return {
  status: 'sucesso',
  resposta_texto: resposta
};

try {
  const rawXml = $input.item.json.data || $input.item.json;
  let novidades = 'Novidade na área! ';

  if (rawXml && rawXml.rss && rawXml.rss.channel && rawXml.rss.channel.item) {
    const posts = Array.isArray(rawXml.rss.channel.item) ? rawXml.rss.channel.item.slice(0, 3) : [rawXml.rss.channel.item];

    let resumo = posts.map((p, index) => {
      let title = p.title || '';
      let link = p.link || 'https://www.instagram.com/ladyrootsilhagrande/';
      return (index + 1) + '. ' + title.substring(0, 60) + '... (Veja mais: ' + link + ')';
    }).join('\n');

    novidades += 'Confira o que está rolando na nossa página nas últimas horas:\n' + resumo;
  } else {
    novidades = 'Para saber o que está acontecendo na ilha agora, de forma em tempo real, acompanhe a gente no Instagram! Dá uma olhada nas nossas últimas postagens: https://instagram.com/ladyrootsilhagrande';
  }

  return [
    {
      json: {
        status: 'sucesso',
        resposta_texto: novidades
      }
    }
  ];
} catch(e) {
  return [
    {
      json: {
        status: 'sucesso',
        resposta_texto: 'Confira as novidades mais recentes no nosso instagram: https://instagram.com/ladyrootsilhagrande'
      }
    }
  ];
}
